 1	import React from 'react';
 2	import classnames from 'classnames';
 3	
 4	import { WizardDescriptionItem } from '@catalog/wizard/components/WizardDescriptionItem';
 5	import { WizardTab } from '@catalog/wizard/tabs';
 6	import AlertScripts from '@kubevirt-utils/components/AlertScripts/AlertScripts';
 7	import { CloudInitDescription } from '@kubevirt-utils/components/CloudinitDescription/CloudInitDescription';
 8	import CloudinitModal from '@kubevirt-utils/components/CloudinitModal/CloudinitModal';
 9	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
10	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
11	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
12	import { OS_NAME_TYPES } from '@kubevirt-utils/resources/template';
13	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
14	import {
15	  DescriptionList,
16	  DescriptionListDescription,
17	  Divider,
18	  PageSection,
19	  PageSectionVariants,
20	} from '@patternfly/react-core';
21	
22	import DynamicSSHKeyInjectionWizard from './components/DynamicSSHKeyInjectionWizard';
23	import SSHKey from './components/SSHKey';
24	import Sysprep from './components/Sysprep';
25	
26	import './WizardScriptsTab.scss';
27	
28	const WizardScriptsTab: WizardTab = ({ tabsData, updateVM, vm }) => {
29	  const { t } = useKubevirtTranslation();
30	  const { createModal } = useModal();
31	
32	  return (
33	    <PageSection className="wizard-scripts-tab" variant={PageSectionVariants.light}>
34	      <SidebarEditor
35	        onResourceUpdate={(newVM) => updateVM(newVM)}
36	        pathsToHighlight={PATHS_TO_HIGHLIGHT.SCRIPTS_TAB}
37	        resource={vm}
38	      >
39	        <DescriptionList
40	          className={classnames('pf-v6-c-description-list', 'wizard-scripts-tab__description-list')}
41	        >
42	          <DescriptionListDescription>
43	            <AlertScripts />
44	          </DescriptionListDescription>
45	          <WizardDescriptionItem
46	            onEditClick={() =>
47	              createModal((modalProps) => (
48	                <CloudinitModal {...modalProps} onSubmit={updateVM} vm={vm} />
49	              ))
50	            }
51	            description={<CloudInitDescription vm={vm} />}
52	            isDisabled={tabsData.overview.templateMetadata.osType === OS_NAME_TYPES.windows}
53	            isEdit
54	            showEditOnTitle
55	            testId="wizard-cloudinit"
56	            title={t('Cloud-init')}
57	          />
58	          <Divider />
59	          <SSHKey />
60	          <Divider />
61	          <DynamicSSHKeyInjectionWizard />
62	          <Divider />
63	          <Sysprep />
64	        </DescriptionList>
65	      </SidebarEditor>
66	    </PageSection>
67	  );
68	};
69	
70	export default WizardScriptsTab;

